CREATE PROCEDURE dbo.Account_BulkMoveUnderParent_Alt
    @NewParentCode   NVARCHAR(50),
    @AccountCodesCsv NVARCHAR(MAX),       -- مثال:  '220501','220502','220503'
    @Reason          NVARCHAR(400) = NULL,
    @BatchId         UNIQUEIDENTIFIER = NULL,
    @MovedByUserId   INT = NULL,
    @MovedByUser     NVARCHAR(100) = NULL,
    @AppName         NVARCHAR(100) = N'VB6'
AS
BEGIN
    SET NOCOUNT ON; SET XACT_ABORT ON;

    IF OBJECT_ID('tempdb..#list') IS NOT NULL DROP TABLE #list;
    CREATE TABLE #list (Account_Code NVARCHAR(50) PRIMARY KEY);

    DECLARE @xml XML;
    SET @xml = CAST(('<r><i>' + REPLACE(REPLACE(@AccountCodesCsv, '''', ''), ',', '</i><i>') + '</i></r>') AS XML);

    INSERT INTO #list(Account_Code)
    SELECT DISTINCT LTRIM(RTRIM(T.c.value('.', 'nvarchar(50)')))
    FROM @xml.nodes('/r/i') AS T(c)
    WHERE LTRIM(RTRIM(T.c.value('.', 'nvarchar(50)'))) <> N'';

    IF NOT EXISTS (SELECT 1 FROM #list) RETURN;

    BEGIN TRY
        BEGIN TRAN;

        DECLARE @ParentSerial NVARCHAR(200), @LevelNo INT, @Digits INT;

        SELECT @ParentSerial = A.Account_Serial
        FROM dbo.ACCOUNTS AS A WITH (UPDLOCK, HOLDLOCK)
        WHERE A.Account_Code = @NewParentCode;

        IF @ParentSerial IS NULL
        BEGIN
            RAISERROR(N'الأب المحدد لا يملك Serial.', 16, 1);
            ROLLBACK TRAN; RETURN;
        END

        SELECT TOP (1) @LevelNo = L.[Level]
        FROM dbo.AccountsLevelsDetails AS L
        WHERE LEN(@ParentSerial) = (SELECT SUM(NoOfDigits) FROM dbo.AccountsLevelsDetails L2 WHERE L2.[Level] <= L.[Level])
        ORDER BY L.[Level];

        SET @LevelNo = ISNULL(@LevelNo, 0) + 1;

        SELECT @Digits = NoOfDigits FROM dbo.AccountsLevelsDetails WHERE [Level] = @LevelNo;
        IF @Digits IS NULL OR @Digits <= 0
        BEGIN
            RAISERROR(N'تعذّر تحديد عدد الخانات للمستوى التالي.', 16, 1);
            ROLLBACK TRAN; RETURN;
        END

        DECLARE @Base INT;
        SELECT @Base = ISNULL(MAX(CAST(RIGHT(Account_Serial, @Digits) AS INT)), 0)
        FROM dbo.ACCOUNTS WITH (UPDLOCK, HOLDLOCK)
        WHERE Parent_Account_Code = @NewParentCode
          AND Account_Serial LIKE @ParentSerial + N'%'
          AND LEN(Account_Serial) = LEN(@ParentSerial) + @Digits;

        ;WITH cte AS
        (
            SELECT A.Account_Code,
                   ROW_NUMBER() OVER (ORDER BY A.Account_Code) AS rn
            FROM dbo.ACCOUNTS A
            JOIN #list L ON L.Account_Code = A.Account_Code
            WHERE ISNULL(A.Parent_Account_Code, N'') <> @NewParentCode
        ),
        toUpdate AS
        (
            SELECT U.Account_Code,
                   NewSerial = @ParentSerial 
                              + RIGHT(REPLICATE(N'0', @Digits) 
                              + CONVERT(VARCHAR(20), @Base + rn), @Digits)
            FROM cte AS U
        )
        UPDATE A
        SET A.Parent_Account_Code = @NewParentCode,
            A.Account_Serial      = TU.NewSerial
        OUTPUT
            DELETED.Account_Code,
            DELETED.Parent_Account_Code,
            DELETED.Account_Serial,
            INSERTED.Parent_Account_Code,
            INSERTED.Account_Serial,
            @Reason,
            @BatchId,
            @MovedByUserId,
            @MovedByUser,
            HOST_NAME(),
            @AppName,
            SYSDATETIME()
        INTO dbo.AccountMoveLog
        (
            Account_Code, OldParentCode, OldSerial,
            NewParentCode, NewSerial,
            Reason, BatchId, MovedByUserId, MovedByUserName, Workstation, AppName, MovedAt
        )
        FROM dbo.ACCOUNTS A
        JOIN toUpdate TU ON TU.Account_Code = A.Account_Code;

        COMMIT TRAN;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRAN;
        DECLARE @msg NVARCHAR(4000) = ERROR_MESSAGE();
        RAISERROR(@msg, 16, 1);
    END CATCH
END

CREATE PROCEDURE dbo.Account_MoveUnderParent
    @AccountCode    NVARCHAR(50),
    @NewParentCode  NVARCHAR(50),
    @Reason         NVARCHAR(400) = NULL,
    @BatchId        UNIQUEIDENTIFIER = NULL,
    @MovedByUserId  INT = NULL,
    @MovedByUser    NVARCHAR(100) = NULL,
    @AppName        NVARCHAR(100) = N'Dynamic',
    @NewSerial      NVARCHAR(200) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    DECLARE @OldParent NVARCHAR(50), @OldSerial NVARCHAR(200);
    DECLARE @ParentSerial NVARCHAR(200);
    DECLARE @LevelNo INT, @Digits INT, @MaxTail INT, @NextNum INT;

    BEGIN TRY
        BEGIN TRAN;

        /* قفل صف الحساب أثناء التحديث */
        SELECT 
            @OldParent = Parent_Account_Code,
            @OldSerial = Account_Serial
        FROM dbo.ACCOUNTS WITH (UPDLOCK, HOLDLOCK)
        WHERE Account_Code = @AccountCode;

        /* سيريال الأب الجديد */
        SELECT @ParentSerial = Account_Serial
        FROM dbo.ACCOUNTS
        WHERE Account_Code = @NewParentCode;

        IF @ParentSerial IS NULL
        BEGIN
            RAISERROR(N'الأب المحدد لا يملك Serial.', 16, 1);
            ROLLBACK TRAN; RETURN;
        END

        /* تحديد مستوى الأب ثم مستوى الابن (Level الأب + 1)
           حساب مستوى الأب يتم بمطابقة طول سيرياله مع مجموع NoOfDigits حتى هذا المستوى */
        SELECT TOP (1) @LevelNo = L.[Level]
        FROM dbo.AccountsLevelsDetails AS L
        WHERE LEN(@ParentSerial) = (
            SELECT SUM(NoOfDigits) FROM dbo.AccountsLevelsDetails L2 WHERE L2.[Level] <= L.[Level]
        )
        ORDER BY L.[Level];

        SET @LevelNo = ISNULL(@LevelNo, 0) + 1;

        SELECT @Digits = NoOfDigits 
        FROM dbo.AccountsLevelsDetails 
        WHERE [Level] = @LevelNo;

        IF @Digits IS NULL OR @Digits <= 0
        BEGIN
            RAISERROR(N'تعذّر تحديد عدد الخانات للمستوى التالي.', 16, 1);
            ROLLBACK TRAN; RETURN;
        END

        /* أكبر ذيل موجود تحت الأب */
        SELECT @MaxTail = MAX(CAST(RIGHT(Account_Serial, @Digits) AS INT))
        FROM dbo.ACCOUNTS
        WHERE Parent_Account_Code = @NewParentCode
          AND Account_Serial LIKE @ParentSerial + N'%'
          AND LEN(Account_Serial) = LEN(@ParentSerial) + @Digits;

        SET @NextNum = ISNULL(@MaxTail, 0) + 1;

        /* توليد السيريال الجديد وضمان عدم التعارض */
        DECLARE @Tail NVARCHAR(50);
        SET @Tail = RIGHT(REPLICATE(N'0', @Digits) + CONVERT(VARCHAR(20), @NextNum), @Digits);
        SET @NewSerial = @ParentSerial + @Tail;

        WHILE EXISTS (SELECT 1 FROM dbo.ACCOUNTS WHERE Account_Serial = @NewSerial)
        BEGIN
            SET @NextNum = @NextNum + 1;
            SET @Tail = RIGHT(REPLICATE(N'0', @Digits) + CONVERT(VARCHAR(20), @NextNum), @Digits);
            SET @NewSerial = @ParentSerial + @Tail;
        END

        /* التحديث */
        UPDATE dbo.ACCOUNTS
        SET Parent_Account_Code = @NewParentCode,
            Account_Serial      = @NewSerial
        WHERE Account_Code = @AccountCode;

        /* اللوج */
        INSERT INTO dbo.AccountMoveLog
        (Account_Code, OldParentCode, OldSerial, NewParentCode, NewSerial,
         Reason, BatchId, MovedByUserId, MovedByUserName, Workstation, AppName)
        VALUES
        (@AccountCode, @OldParent, @OldSerial, @NewParentCode, @NewSerial,
         @Reason, @BatchId, @MovedByUserId, @MovedByUser, HOST_NAME(), @AppName);

        COMMIT TRAN;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRAN;
        DECLARE @msg NVARCHAR(4000) = ERROR_MESSAGE();
        RAISERROR(@msg, 16, 1);
    END CATCH
END

/*
**	Retrieve the owner object(s) of a given property
*/
create procedure dbo.dt_getobjwithprop
	@property varchar(30),
	@value varchar(255)
as
	set nocount on

	if (@property is null) or (@property = '')
	begin
		raiserror('Must specify a property name.',-1,-1)
		return (1)
	end

	if (@value is null)
		select objectid id from dbo.dtproperties
			where property=@property

	else
		select objectid id from dbo.dtproperties
			where property=@property and value=@value

/*
**	Retrieve the owner object(s) of a given property
*/
create procedure dbo.dt_getobjwithprop_u
	@property varchar(30),
	@uvalue nvarchar(255)
as
	set nocount on

	if (@property is null) or (@property = '')
	begin
		raiserror('Must specify a property name.',-1,-1)
		return (1)
	end

	if (@uvalue is null)
		select objectid id from dbo.dtproperties
			where property=@property

	else
		select objectid id from dbo.dtproperties
			where property=@property and uvalue=@uvalue

create procedure dbo.dt_getpropertiesbyid_vcs
    @id       int,
    @property varchar(64),
    @value    varchar(255) = NULL OUT

as

    set nocount on

    select @value = (
        select value
                from dbo.dtproperties
                where @id=objectid and @property=property
                )

create procedure dbo.dt_getpropertiesbyid_vcs_u
    @id       int,
    @property varchar(64),
    @value    nvarchar(255) = NULL OUT

as

    set nocount on

    select @value = (
        select uvalue
                from dbo.dtproperties
                where @id=objectid and @property=property
                )

----------------------------------------------------
-- ستورد بروسيجر الصيانة السريعة/الخفيفة
----------------------------------------------------
CREATE PROCEDURE dbo.usp_QuickDbMaintenance
(
      @ReorganizeFrom   FLOAT = 10    -- من نسبة فراجمنتشن كام يبدأ يعمل REORGANIZE
    , @MinPageCount     INT   = 200   -- تجاهل الإندكسات الصغيرة (أقل من كذا صفحة)
    , @PreviewOnly      BIT   = 0     -- لو 1: يطبع الأوامر بس من غير تنفيذ (للمراجعة)
)
AS
BEGIN
    SET NOCOUNT ON;

    PRINT '===============================================';
    PRINT 'بدء الصيانة السريعة للداتا بيز: ' + DB_NAME();
    PRINT 'التاريخ/الوقت: ' + CONVERT(NVARCHAR(30), GETDATE(), 120);
    PRINT '===============================================';

    ------------------------------------------------
    -- 1) REORGANIZE للإندكسات ذات الفراجمنتشن المتوسط
    ------------------------------------------------
    PRINT 'الخطوة 1: حساب الفراجمنتشن وعمل REORGANIZE للإندكسات المتفرجمنتة...';

    IF OBJECT_ID('tempdb..#FragQuick') IS NOT NULL DROP TABLE #FragQuick;

    SELECT 
          t.name      AS TableName
        , s.name      AS SchemaName
        , i.name      AS IndexName
        , ips.index_id
        , ips.avg_fragmentation_in_percent AS FragPercent
        , ips.page_count
    INTO #FragQuick
    FROM sys.dm_db_index_physical_stats(DB_ID(), NULL, NULL, NULL, 'LIMITED') ips
    JOIN sys.indexes i   ON ips.object_id = i.object_id AND ips.index_id = i.index_id
    JOIN sys.tables t    ON t.object_id  = i.object_id
    JOIN sys.schemas s   ON t.schema_id = s.schema_id
    WHERE 
        i.type IN (1,2)              -- clustered, nonclustered
        AND ips.page_count >= @MinPageCount
        AND t.is_ms_shipped = 0
        AND ips.avg_fragmentation_in_percent >= @ReorganizeFrom;

    DECLARE 
          @TableName   SYSNAME
        , @SchemaName  SYSNAME
        , @IndexName   SYSNAME
        , @IndexId     INT
        , @Frag        FLOAT
        , @SQL         NVARCHAR(MAX);

    DECLARE curQuick CURSOR LOCAL FAST_FORWARD FOR
        SELECT TableName, SchemaName, IndexName, index_id, FragPercent
        FROM #FragQuick
        ORDER BY FragPercent DESC;

    OPEN curQuick;
    FETCH NEXT FROM curQuick INTO @TableName, @SchemaName, @IndexName, @IndexId, @Frag;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        SET @SQL = N'ALTER INDEX [' + @IndexName + N'] ON [' 
                    + @SchemaName + N'].[' + @TableName + N'] REORGANIZE;';

        PRINT '-- Frag = ' + CONVERT(NVARCHAR(10), @Frag) 
              + ' | ' + @SchemaName + '.' + @TableName + ' -> ' + @IndexName;
        PRINT @SQL;

        IF @PreviewOnly = 0
        BEGIN
            BEGIN TRY
                EXEC (@SQL);
            END TRY
            BEGIN CATCH
                PRINT 'خطأ أثناء REORGANIZE للإندكس: '
                      + ISNULL(@SchemaName,'') + '.' + ISNULL(@TableName,'')
                      + ' - ' + ISNULL(@IndexName,'')
                      + ' => ' + ERROR_MESSAGE();
            END CATCH;
        END

        FETCH NEXT FROM curQuick INTO @TableName, @SchemaName, @IndexName, @IndexId, @Frag;
    END

    CLOSE curQuick;
    DEALLOCATE curQuick;

    PRINT 'انتهاء خطوة REORGANIZE.';
    PRINT '-----------------------------------------------';

    ------------------------------------------------
    -- 2) تحديث إحصائيات خفيف باستخدام sp_updatestats
    ------------------------------------------------
    PRINT 'الخطوة 2: تحديث الإحصائيات باستخدام sp_updatestats (خفيفة)...';

    IF @PreviewOnly = 0
    BEGIN
        -- sp_updatestats يقوم بتحديث الإحصائيات للجداول التي تم تعديل بياناتها فقط
        EXEC sp_updatestats;
    END
    ELSE
    BEGIN
        PRINT 'PreviewOnly = 1 => تم تخطي تنفيذ sp_updatestats (عرض فقط).';
    END

    PRINT 'انتهاء الصيانة السريعة للداتا بيز.';
    PRINT '===============================================';

END
